using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild(args[0]);
var errors = new List<(string project, string code, string file, int line, string message)>();
var warnings = new List<(string project, string code, string file, int line, string message)>();

build.VisitAllChildren<Error>(e => {
    var proj = "";
    var parent = e.Parent;
    while (parent != null) {
        if (parent is Project p) { proj = p.Name; break; }
        parent = (parent as TreeNode)?.Parent as BaseNode;
    }
    errors.Add((proj, e.Code ?? "", e.File ?? "", e.LineNumber, e.Text ?? ""));
});

build.VisitAllChildren<Warning>(w => {
    var proj = "";
    var parent = w.Parent;
    while (parent != null) {
        if (parent is Project p) { proj = p.Name; break; }
        parent = (parent as TreeNode)?.Parent as BaseNode;
    }
    warnings.Add((proj, w.Code ?? "", w.File ?? "", w.LineNumber, w.Text ?? ""));
});

Console.WriteLine($"=== ERRORS ({errors.Count}) ===");
foreach (var (proj, code, file, line, msg) in errors)
    Console.WriteLine($"[{proj}] {code} {file}({line}): {msg}");

Console.WriteLine($"\n=== WARNINGS ({warnings.Count}) ===");
foreach (var (proj, code, file, line, msg) in warnings.Take(50))
    Console.WriteLine($"[{proj}] {code} {file}({line}): {msg}");
EOF

