using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild(args[0]);

// Check build result
Console.WriteLine($"Build succeeded: {build.Succeeded}");

// Check for project dependency info
Console.WriteLine("\n=== PROJECT REFERENCES (from items) ===");
build.VisitAllChildren<AddItem>(item => {
    if (item.Name == "ProjectReference") {
        BaseNode parent = item.Parent;
        string proj = "";
        while (parent != null) {
            if (parent is Project p) { proj = p.Name; break; }
            if (parent is TreeNode tn) parent = tn.Parent;
            else break;
        }
        foreach (var child in item.Children) {
            Console.WriteLine($"  {proj} -> {child}");
        }
    }
});

// Check for failed targets
Console.WriteLine("\n=== FAILED TARGETS ===");
build.VisitAllChildren<Target>(t => {
    if (!t.Succeeded) {
        BaseNode parent = t.Parent;
        string proj = "";
        while (parent != null) {
            if (parent is Project p) { proj = p.Name; break; }
            if (parent is TreeNode tn) parent = tn.Parent;
            else break;
        }
        Console.WriteLine($"  [{proj}] Target '{t.Name}' FAILED");
    }
});
EOF
